import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"102. Hsrs","description":"","frontmatter":{"title":"102. Hsrs","eba":"Allied Health Professionals 2021-2026","topics":["ohs"]},"headers":[],"relativePath":"ebas/allied-health/ohs/102-hsrs.md","filePath":"ebas/allied-health/ohs/102-hsrs.md"}'),a={name:"ebas/allied-health/ohs/102-hsrs.md"};function n(i,e,l,h,p,d){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_102-hsrs" tabindex="-1">102. Hsrs <a class="header-anchor" href="#_102-hsrs" aria-label="Permalink to &quot;102. Hsrs&quot;">​</a></h1><p><strong>102.1</strong> HSR(s) Election Process</p><p><strong>(a)</strong> All Employees in the relevant DWG will be given the opportunity to nominate for a position as an HSR.</p><p><strong>(b)</strong> Where there is more than one (1) nominee for any vacancy of an HSR position, the method of conducting the election shall be determined by the Employees of the DWG concerned. The Union will, where requested by the staff, conduct the election.</p><p><strong>(c)</strong> If there is equivalent nominees to positions vacant then the candidate(s) will be elected unopposed.</p><p><strong>(d)</strong> The Employer will maintain a current list of DWGs as well as the name(s) of the elected HSR(s) for each DWG and shall display this in a prominent place in the workplace at all times.</p><p><strong>(e)</strong> Employers will provide a copy of the DWG list, with the names of the HSR(s), their respective training dates and their respective election dates to the Union at least annually or within 28 days of receiving a written request from the Union.</p><p><strong>102.2</strong> HSR Training</p><p><strong>(a)</strong> HSRs will be entitled and encouraged to attend a WorkSafe Victoria approved course as soon as practicable following their election.</p><p><strong>(b)</strong> The Employer will permit HSRs to take such time as is necessary or prescribed to attend occupational health and safety training courses approved by WorkSafe Victoria.</p><p><strong>(c)</strong> HSRs will have the right to choose which course to attend, provided it is a WorkSafe Victoria approved course. An Employer will not prevent or obstruct an HSR from attending course chosen by them.</p><p><strong>(d)</strong> When attending an approved course, HSRs shall be paid as per their roster, that is the normal/expected earnings during course attendance, including but not limited to pay entitlements relating to shift work, regular overtime, higher duties, allowances or penalty rates that would have applied had the HSR been at work.</p><p><strong>(e)</strong> Where HSRs attend an approved course outside their normal working hours or roster, they will be paid as if they had been at work for the relevant time, including any relevant overtime rates, higher rates, allowances or penalty rates. This might apply when an HSR:</p><p><strong>(i)</strong> normally works two (2) days a week, and attends a block five (5) day course;</p><p><strong>(ii)</strong> has a rostered day off during the course; and</p><p><strong>(iii)</strong> has a shift that does not overlap, or overlaps only marginally, with the course&#39;s hours.</p><p><strong>(f)</strong> Rosters or shifts prior to/post HSR training shall be altered where necessary to ensure that HSRs are not exposed to extra risks from fatigue due to working extended hours or shiftwork while attending a training course.</p><p><strong>(g)</strong> The Employer is responsible for payment of course fees, travel costs and accommodation for HSR attendance at WorkSafe Victoria approved courses.</p><p><strong>102.3</strong> Facilities for HSRs</p><p><strong>(a)</strong> HSRs will be provided with reasonable access to an office, telephone, computer (including email facilities where available), notice board, meeting room, and such other facilities as are necessary to enable them to perform their functions or duties as prescribed under the OHS Act.</p><p><strong>(b)</strong> HSRs will have reasonable time release from duty to perform their functions and duties as is necessary or prescribed under the OHS Act.</p><p><strong>102.4</strong> Health and Safety Committees Health and safety committees will be established where requested by a HSR.</p>',22)])])}const f=t(a,[["render",n]]);export{g as __pageData,f as default};
